def generate_pascals_triangle(num_rows):
    if num_rows <= 0:
        return []

    triangle = []

    for i in range(num_rows):
        current_row = [1] * (i + 1)

        # Calculate inner elements for rows starting from the third row (index 2)
        if i >= 2:
            prev_row = triangle[i - 1]
            for j in range(1, i):
                current_row[j] = prev_row[j - 1] + prev_row[j]

        triangle.append(current_row)

    return triangle
